p.m:
\displaystyle{\begin{aligned}
   20\div \frac{5}{3} 
       \amp = \frac{20}{1} \div \frac{5}{3} \\
       \amp = \frac{20}{1} \cdot \frac{3}{5} \amp \hbox{We can divide 20 and 5 by 5 and made those two values smaller.}\\
       \amp = \frac{4}{1}\cdot\frac{3}{1} \\
       \amp = \frac{4\cdot3}{1 \cdot 1} \\
       \amp = 12
\end{aligned}
    }
